interface Order {
  id: string;
  amount: number;
  status: "pending" | "paid" | "cancelled";
}

const orders: Order[] = [
  { id: "O1", amount: 249, status: "paid"      },
  { id: "O2", amount: 49,  status: "pending"   },
  { id: "O3", amount: 199, status: "paid"      },
  { id: "O4", amount: 99,  status: "cancelled" },
  { id: "O5", amount: 149, status: "paid"      },
];

const paid = orders.filter(o => o.status === "paid");
const revenue = paid.reduce((sum, o) => sum + o.amount, 0);

console.log(`Total orders: ${orders.length}`);
console.log(`Paid: ${paid.length}`);
console.log(`Revenue: $${revenue}`);

interface Order {
  customerId: number;
  product: string;
  amount: number;
}

const orders: Order[] = [
  { customerId: 1, product: "Pro Plan",        amount: 49  },
  { customerId: 2, product: "Enterprise Plan",  amount: 199 },
  { customerId: 1, product: "Support Add-on",   amount: 29  },
  { customerId: 3, product: "Starter Plan",     amount: 19  },
  { customerId: 2, product: "Training Package", amount: 299 },
];

const byCustomer = orders.reduce<Record<number, number>>((acc, order) => {
  acc[order.customerId] = (acc[order.customerId] ?? 0) + order.amount;
  return acc;
}, {});

for (const [customerId, total] of Object.entries(byCustomer)) {
  console.log(`Customer ${customerId}: $${total}`);
}

