interface Player {
  name: string;
  score: number;
  level: number;
}

const players: Player[] = [
  { name: "Charlie", score: 1850, level: 5 },
  { name: "Alice",   score: 2850, level: 8 },
  { name: "Bob",     score: 1200, level: 3 },
  { name: "Diana",   score: 3100, level: 9 },
];

// Sort by score descending (doesn't mutate original)
const leaderboard = [...players].sort((a, b) => b.score - a.score);

console.log("Leaderboard:");
leaderboard.forEach((p, i) => {
  console.log(`${i + 1}. ${p.name}: ${p.score} pts (lvl ${p.level})`);
});

interface Category {
  name: string;
  items: string[];
}

const catalog: Category[] = [
  { name: "Frontend",  items: ["HTML", "CSS", "JavaScript", "TypeScript"] },
  { name: "Backend",   items: ["Node.js", "Python", "Go"]                 },
  { name: "Database",  items: ["SQL", "PostgreSQL", "Redis"]              },
];

// All items in a flat list
const allItems = catalog.flatMap(cat => cat.items);

// All items with their category
const tagged = catalog.flatMap(cat =>
  cat.items.map(item => `${cat.name}/${item}`)
);

console.log(`Total items: ${allItems.length}`);
console.log(`First 4: ${allItems.slice(0, 4).join(", ")}`);
console.log(`Tagged sample: ${tagged.slice(0, 3).join(", ")}`);

