const SUPPORTED_LANGUAGES: readonly string[] = [
  "go", "python", "typescript", "javascript", "java", "rust", "csharp", "sql"
];

const HTTP_SUCCESS_CODES: readonly number[] = [200, 201, 204];
const HTTP_ERROR_CODES: readonly number[] = [400, 401, 403, 404, 500];

// SUPPORTED_LANGUAGES.push("ruby");  // ← Error: Property 'push' does not exist

function isValidLanguage(lang: string): boolean {
  return SUPPORTED_LANGUAGES.includes(lang);
}

function isSuccessCode(code: number): boolean {
  return HTTP_SUCCESS_CODES.includes(code);
}

console.log(`Valid: go=${isValidLanguage("go")}, ruby=${isValidLanguage("ruby")}`);
console.log(`200 is success: ${isSuccessCode(200)}`);
console.log(`Languages count: ${SUPPORTED_LANGUAGES.length}`);

const frontend = ["HTML", "CSS", "JavaScript"];
const backend  = ["Node.js", "Python", "Go"];
const devops   = ["Docker", "Kubernetes"];

// Combine without mutating originals
const fullStack = [...frontend, "TypeScript", ...backend];
const allSkills = [...frontend, ...backend, ...devops];

// Clone and modify
const updatedFrontend = [...frontend, "TypeScript", "React"];

console.log(`Full stack (${fullStack.length}): ${fullStack.join(", ")}`);
console.log(`All skills (${allSkills.length}): ${allSkills.join(", ")}`);
console.log(`Updated frontend: ${updatedFrontend.join(", ")}`);

interface FormField {
  name: string;
  value: string;
  required: boolean;
}

const fields: FormField[] = [
  { name: "username", value: "alice",             required: true  },
  { name: "email",    value: "alice@example.com",  required: true  },
  { name: "bio",      value: "",                  required: false },
  { name: "website", value: "https://alice.dev",  required: false },
];

const allRequiredFilled = fields
  .filter(f => f.required)
  .every(f => f.value.trim() !== "");

const hasEmptyFields = fields.some(f => f.value.trim() === "");

const filledCount = fields.filter(f => f.value !== "").length;

console.log(`Form valid: ${allRequiredFilled}`);
console.log(`Has empty fields: ${hasEmptyFields}`);
console.log(`Filled: ${filledCount}/${fields.length} fields`);

type LoginEvent  = { type: "login";  userId: number; timestamp: string };
type LogoutEvent = { type: "logout"; userId: number; timestamp: string };
type ErrorEvent  = { type: "error";  message: string; code: number };

type AppEvent = LoginEvent | LogoutEvent | ErrorEvent;

const events: AppEvent[] = [
  { type: "login",  userId: 1, timestamp: "2024-01-15T10:00:00Z" },
  { type: "error",  message: "DB timeout", code: 503 },
  { type: "login",  userId: 2, timestamp: "2024-01-15T10:01:00Z" },
  { type: "logout", userId: 1, timestamp: "2024-01-15T10:30:00Z" },
  { type: "error",  message: "Auth failed", code: 401 },
];

const logins = events.filter((e): e is LoginEvent => e.type === "login");
const errors = events.filter((e): e is ErrorEvent => e.type === "error");

console.log(`Logins: ${logins.map(e => `user ${e.userId}`).join(", ")}`);
console.log(`Errors: ${errors.map(e => `${e.code} ${e.message}`).join(" | ")}`);
console.log(`Total events: ${events.length}`);
